def fmt(n):
    return f"{n:,.0f}".replace(",", " ")

def page(path, title, desc, h1, crumbs, body_html, related, jsonld=None):
    """Собирает страницу и пишет на диск. path вида 'npd/repetitor'."""
    canon = f"{SITE}/{path}/"
    rel_html = ""
    if related:
        items = "".join(f'<li><a href="{u}">{html.escape(t)}</a></li>' for t, u in related)
        rel_html = f'<div class="rel"><b>Читайте также</b><ul>{items}</ul></div>'
    ld = f'<script type="application/ld+json">{jsonld}</script>' if jsonld else ""
    bc = {"@context":"https://schema.org","@type":"BreadcrumbList","itemListElement":[
        {"@type":"ListItem","position":1,"name":"Самосчёт","item":"https://samoschet.online/"},
        {"@type":"ListItem","position":2,"name":"База знаний","item":"https://samoschet.online/baza/"},
        {"@type":"ListItem","position":3,"name":crumbs,"item":canon}]}
    import json as _j
    ld += f'<script type="application/ld+json">{_j.dumps(bc, ensure_ascii=False)}</script>'
    doc = f"""<!DOCTYPE html>
<html lang="ru">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>{html.escape(title)}</title>
<meta name="description" content="{html.escape(desc)}">
<link rel="canonical" href="{canon}">
<link rel="icon" type="image/svg+xml" href="/favicon.svg">
<meta property="og:type" content="article">
<meta property="og:site_name" content="Самосчёт">
<meta property="og:locale" content="ru_RU">
<meta property="og:title" content="{html.escape(title)}">
<meta property="og:description" content="{html.escape(desc)}">
<meta property="og:url" content="{canon}">
<meta property="og:image" content="https://samoschet.online/og.png">
<meta name="twitter:card" content="summary_large_image">
<link rel="preconnect" href="https://fonts.googleapis.com">
<link rel="preconnect" href="https://fonts.gstatic.com" crossorigin>
<link href="https://fonts.googleapis.com/css2?family=PT+Serif:ital,wght@0,400;0,700;1,400&display=swap" rel="stylesheet">
{ld}<style>{CSS}</style>
</head>
<body>
<header><div class="wrap">
  <a class="logo" href="/">Само<span>счёт</span></a>
  <nav><a href="/baza/">База знаний</a><a href="/app.html">Инструмент</a></nav>
</div></header>
<div class="wrap">
<div class="crumbs"><a href="/">Самосчёт</a> → <a href="/baza/">База знаний</a> → {html.escape(crumbs)}</div>
<h1>{html.escape(h1)}</h1>
{body_html}
<div class="cta"><b>Проверьте свою выписку за 30 секунд</b>
<p>Бесплатный инструмент Самосчёт разберёт CSV-выписку из любого банка: отделит доход от личных переводов, посчитает налог НПД с вычетом и соберёт отчёт по месяцам. Без регистрации, данные не покидают браузер.</p>
<a href="/app.html">Открыть Самосчёт</a></div>
{rel_html}
</div>
<footer><div class="wrap">Самосчёт · <a href="/">ИИ-бухгалтерия для самозанятых</a> · Материал носит справочный характер и не является налоговой консультацией. Обновлено: {TODAY}.</div></footer>
</body>
</html>"""
    d = os.path.join(ROOT, path)
    os.makedirs(d, exist_ok=True)
    with open(os.path.join(d, "index.html"), "w", encoding="utf-8") as f:
        f.write(doc)
    return canon

