    canon_list = [SITE + "/", SITE + "/app.html", SITE + "/kalkulyator/", srav_url, hub_url, slovar_hub, gid_hub] + [u[0] for u in all_urls]
    sitemap(canon_list)
    robots()
    llms_txt(canon_list)
    print(f"generated {len(all_urls)} pages + hubs; sitemap has {len(canon_list)} urls")
